import{_ as e,o as r,c as d,ag as a}from"./chunks/framework.6MCaaFDc.js";const b=JSON.parse('{"title":"Wireless Networking","description":"","frontmatter":{},"headers":[],"relativePath":"theory/networks/wireless.md","filePath":"theory/networks/wireless.md"}'),o={name:"theory/networks/wireless.md"};function s(i,t,n,l,h,c){return r(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="wireless-networking" tabindex="-1">Wireless Networking <a class="header-anchor" href="#wireless-networking" aria-label="Permalink to &quot;Wireless Networking&quot;">​</a></h1><p>Cut the cable — wireless networking has made it possible to connect devices without a single wire. From the Wi-Fi in your home to 5G on your phone to Bluetooth in your earphones, wireless technology covers a wide range of standards, speeds, and distances.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 11</p><p>Wireless networking is a Grade 11 topic. Know the different wireless technologies, their ranges, speeds, and use cases.</p></div><hr><h2 id="why-wireless" tabindex="-1">Why Wireless? <a class="header-anchor" href="#why-wireless" aria-label="Permalink to &quot;Why Wireless?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Advantage</th><th>Explanation</th></tr></thead><tbody><tr><td><strong>Mobility</strong></td><td>Move freely within range — no physical connection needed</td></tr><tr><td><strong>Easy installation</strong></td><td>No cables to run through walls</td></tr><tr><td><strong>Scalability</strong></td><td>Add devices without adding cable infrastructure</td></tr><tr><td><strong>Accessibility</strong></td><td>Connect in places where cabling is impractical</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Disadvantage</th><th>Explanation</th></tr></thead><tbody><tr><td><strong>Security</strong></td><td>Signals can be intercepted — encryption is essential</td></tr><tr><td><strong>Interference</strong></td><td>Other wireless devices, walls, appliances reduce signal</td></tr><tr><td><strong>Speed</strong></td><td>Generally slower than wired equivalents</td></tr><tr><td><strong>Range</strong></td><td>Signal weakens with distance</td></tr><tr><td><strong>Reliability</strong></td><td>Susceptible to environmental factors</td></tr></tbody></table><hr><h2 id="wi-fi-ieee-802-11" tabindex="-1">Wi-Fi (IEEE 802.11) <a class="header-anchor" href="#wi-fi-ieee-802-11" aria-label="Permalink to &quot;Wi-Fi (IEEE 802.11)&quot;">​</a></h2><p><strong>Wi-Fi</strong> is a wireless LAN technology based on the IEEE 802.11 family of standards. It connects devices to a local network (and through it, to the internet) via a Wireless Access Point (WAP) or router.</p><h3 id="wi-fi-standards" tabindex="-1">Wi-Fi Standards <a class="header-anchor" href="#wi-fi-standards" aria-label="Permalink to &quot;Wi-Fi Standards&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Standard</th><th>Common Name</th><th>Max Speed</th><th>Frequency</th><th>Year</th></tr></thead><tbody><tr><td>802.11g</td><td>Wi-Fi 3</td><td>54 Mbps</td><td>2.4 GHz</td><td>2003</td></tr><tr><td>802.11n</td><td>Wi-Fi 4</td><td>600 Mbps</td><td>2.4 / 5 GHz</td><td>2009</td></tr><tr><td>802.11ac</td><td>Wi-Fi 5</td><td>3.5 Gbps</td><td>5 GHz</td><td>2013</td></tr><tr><td>802.11ax</td><td>Wi-Fi 6</td><td>9.6 Gbps</td><td>2.4 / 5 / 6 GHz</td><td>2019</td></tr></tbody></table><h3 id="_2-4-ghz-vs-5-ghz" tabindex="-1">2.4 GHz vs 5 GHz <a class="header-anchor" href="#_2-4-ghz-vs-5-ghz" aria-label="Permalink to &quot;2.4 GHz vs 5 GHz&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>2.4 GHz</th><th>5 GHz</th></tr></thead><tbody><tr><td>Range</td><td>Longer (through walls better)</td><td>Shorter</td></tr><tr><td>Speed</td><td>Slower</td><td>Faster</td></tr><tr><td>Interference</td><td>More crowded</td><td>Less crowded</td></tr><tr><td>Best for</td><td>Devices far from router</td><td>Devices near router, streaming</td></tr></tbody></table><h3 id="wi-fi-security-protocols" tabindex="-1">Wi-Fi Security Protocols <a class="header-anchor" href="#wi-fi-security-protocols" aria-label="Permalink to &quot;Wi-Fi Security Protocols&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Protocol</th><th>Year</th><th>Security Level</th><th>Notes</th></tr></thead><tbody><tr><td>WEP</td><td>1999</td><td>Weak</td><td>Easily cracked — obsolete</td></tr><tr><td>WPA</td><td>2003</td><td>Moderate</td><td>Improved over WEP</td></tr><tr><td>WPA2</td><td>2004</td><td>Strong</td><td>AES encryption — current standard</td></tr><tr><td>WPA3</td><td>2018</td><td>Very strong</td><td>Latest — protects against dictionary attacks</td></tr></tbody></table><div class="warning custom-block github-alert"><p class="custom-block-title">Always use WPA2 or WPA3</p><p>WEP and WPA are no longer secure. Networks using WEP can be cracked in minutes with freely available tools.</p></div><hr><h2 id="bluetooth" tabindex="-1">Bluetooth <a class="header-anchor" href="#bluetooth" aria-label="Permalink to &quot;Bluetooth&quot;">​</a></h2><p><strong>Bluetooth</strong> is a short-range wireless technology for connecting personal devices.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Detail</th></tr></thead><tbody><tr><td>Standard</td><td>IEEE 802.15</td></tr><tr><td>Range</td><td>~10 m (Class 2), up to 100 m (Class 1)</td></tr><tr><td>Speed</td><td>Up to 3 Mbps (classic), 2 Mbps (BLE)</td></tr><tr><td>Frequency</td><td>2.4 GHz</td></tr><tr><td>Power</td><td>Very low (especially Bluetooth Low Energy / BLE)</td></tr></tbody></table><p><strong>Uses:</strong> wireless earphones, keyboards, mice, smartwatches, speakers, file transfer between phones, car audio systems</p><p><strong>Bluetooth Low Energy (BLE):</strong></p><ul><li>Used in IoT devices, fitness trackers, medical devices</li><li>Battery lasts months on a single cell</li></ul><hr><h2 id="wimax" tabindex="-1">WiMAX <a class="header-anchor" href="#wimax" aria-label="Permalink to &quot;WiMAX&quot;">​</a></h2><p><strong>WiMAX</strong> (Worldwide Interoperability for Microwave Access) is a long-range wireless technology providing broadband internet over large areas.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Detail</th></tr></thead><tbody><tr><td>Standard</td><td>IEEE 802.16</td></tr><tr><td>Range</td><td>Up to 50 km</td></tr><tr><td>Speed</td><td>Up to 70 Mbps</td></tr><tr><td>Use case</td><td>Providing internet to rural areas; MAN</td></tr></tbody></table><p><strong>Purpose:</strong> Delivers internet access where fibre or cable infrastructure doesn&#39;t exist — rural areas, developing regions.</p><p>Now largely superseded by 4G LTE for mobile coverage, but still used in some deployments.</p><hr><h2 id="mobile-data-networks-cellular" tabindex="-1">Mobile Data Networks (Cellular) <a class="header-anchor" href="#mobile-data-networks-cellular" aria-label="Permalink to &quot;Mobile Data Networks (Cellular)&quot;">​</a></h2><p>Cellular networks provide internet and communication via a network of base stations (towers).</p><table tabindex="0"><thead><tr><th>Generation</th><th>Speed</th><th>Latency</th><th>Key Uses</th></tr></thead><tbody><tr><td><strong>2G (GSM)</strong></td><td>~0.1 Mbps</td><td>High</td><td>Voice calls, SMS</td></tr><tr><td><strong>3G (UMTS)</strong></td><td>2–42 Mbps</td><td>~100 ms</td><td>Mobile internet, video calls</td></tr><tr><td><strong>4G LTE</strong></td><td>10–150 Mbps</td><td>30–50 ms</td><td>HD streaming, mobile apps, hotspots</td></tr><tr><td><strong>5G</strong></td><td>100 Mbps–10 Gbps</td><td>&lt;10 ms</td><td>IoT, autonomous vehicles, AR/VR, smart cities</td></tr></tbody></table><h3 id="_4g-vs-5g" tabindex="-1">4G vs 5G <a class="header-anchor" href="#_4g-vs-5g" aria-label="Permalink to &quot;4G vs 5G&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>4G LTE</th><th>5G</th></tr></thead><tbody><tr><td>Max speed</td><td>~150 Mbps</td><td>~10 Gbps</td></tr><tr><td>Latency</td><td>30–50 ms</td><td>&lt;1 ms</td></tr><tr><td>Device density</td><td>Moderate</td><td>Very high (IoT)</td></tr><tr><td>Coverage</td><td>Widespread globally</td><td>Still expanding</td></tr><tr><td>Infrastructure</td><td>Existing towers</td><td>New towers required (mmWave)</td></tr><tr><td>Main benefit</td><td>Fast mobile internet</td><td>Ultra-low latency + massive IoT</td></tr></tbody></table><hr><h2 id="nfc-—-near-field-communication" tabindex="-1">NFC — Near Field Communication <a class="header-anchor" href="#nfc-—-near-field-communication" aria-label="Permalink to &quot;NFC — Near Field Communication&quot;">​</a></h2><p><strong>NFC</strong> enables very short-range (&lt; 4 cm) wireless communication between devices.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Detail</th></tr></thead><tbody><tr><td>Range</td><td>&lt; 4 cm</td></tr><tr><td>Speed</td><td>~400 Kbps</td></tr><tr><td>Use case</td><td>Contactless payment, tap-to-pair, access cards</td></tr></tbody></table><p><strong>Examples:</strong> Apple Pay, Google Pay, tap-to-pay bank cards, hotel room key cards, tap-to-connect Bluetooth speakers</p><hr><h2 id="rfid-—-radio-frequency-identification" tabindex="-1">RFID — Radio Frequency Identification <a class="header-anchor" href="#rfid-—-radio-frequency-identification" aria-label="Permalink to &quot;RFID — Radio Frequency Identification&quot;">​</a></h2><p><strong>RFID</strong> uses radio waves to read data from passive or active tags without physical contact.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Detail</th></tr></thead><tbody><tr><td>Range</td><td>cm to several metres (depends on frequency)</td></tr><tr><td>Power</td><td>Passive (no battery) or active (battery)</td></tr><tr><td>Use case</td><td>Inventory tracking, library books, access control, toll gates, livestock tracking</td></tr></tbody></table><p><strong>Passive RFID:</strong> the reader powers the tag via radio waves — no battery needed in the tag.</p><hr><h2 id="wireless-technology-comparison" tabindex="-1">Wireless Technology Comparison <a class="header-anchor" href="#wireless-technology-comparison" aria-label="Permalink to &quot;Wireless Technology Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Technology</th><th>Range</th><th>Speed</th><th>Use Case</th></tr></thead><tbody><tr><td>Bluetooth</td><td>&lt; 10 m</td><td>Low</td><td>Personal devices</td></tr><tr><td>NFC</td><td>&lt; 4 cm</td><td>Very low</td><td>Payments, pairing</td></tr><tr><td>Wi-Fi (802.11ac)</td><td>~50 m indoors</td><td>Up to 3.5 Gbps</td><td>LAN wireless</td></tr><tr><td>4G LTE</td><td>City-wide</td><td>10–150 Mbps</td><td>Mobile internet</td></tr><tr><td>5G</td><td>City-wide</td><td>Up to 10 Gbps</td><td>IoT, ultra-low latency</td></tr><tr><td>WiMAX</td><td>Up to 50 km</td><td>Up to 70 Mbps</td><td>Rural broadband</td></tr><tr><td>RFID</td><td>cm–metres</td><td>Very low</td><td>Tracking, access</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Wi-Fi</strong></td><td>Wireless LAN technology (IEEE 802.11)</td></tr><tr><td><strong>WAP</strong></td><td>Wireless Access Point — connects wireless devices to a wired LAN</td></tr><tr><td><strong>SSID</strong></td><td>Name of a Wi-Fi network broadcast by a WAP</td></tr><tr><td><strong>WPA2</strong></td><td>Wi-Fi security protocol using AES encryption</td></tr><tr><td><strong>Bluetooth</strong></td><td>Short-range wireless standard for personal devices</td></tr><tr><td><strong>BLE</strong></td><td>Bluetooth Low Energy — for IoT and wearable devices</td></tr><tr><td><strong>WiMAX</strong></td><td>Long-range wireless broadband (IEEE 802.16)</td></tr><tr><td><strong>4G LTE</strong></td><td>4th generation mobile network — fast mobile internet</td></tr><tr><td><strong>5G</strong></td><td>5th generation network — ultra-fast, ultra-low latency</td></tr><tr><td><strong>NFC</strong></td><td>Near Field Communication — &lt; 4 cm range, used for payments</td></tr><tr><td><strong>RFID</strong></td><td>Radio Frequency Identification — tracking via radio tags</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;What is the difference between 4G and 5G?&quot;</strong> — 5G is much faster (up to 10 Gbps vs 150 Mbps); 5G has lower latency (&lt;1 ms vs 30–50 ms); 5G supports higher device density for IoT; 4G has wider coverage currently</p></li><li><p><strong>&quot;Give TWO advantages of wireless networking over wired&quot;</strong> — no cables needed (easy installation, mobility); can connect in locations where cabling is impractical</p></li><li><p><strong>&quot;Give TWO disadvantages of wireless networking&quot;</strong> — security risk (signals can be intercepted); interference from walls and other devices; generally slower than wired</p></li><li><p><strong>&quot;What is WPA2? Why is WEP no longer recommended?&quot;</strong> — WPA2 is a Wi-Fi security protocol using AES encryption; WEP is easily cracked with freely available tools</p></li><li><p><strong>&quot;Give ONE use of Bluetooth and ONE use of NFC&quot;</strong> — Bluetooth: wireless earphones / keyboard; NFC: contactless payment (Apple Pay/Google Pay) / tap to pair</p></li></ol></div>',55)])])}const p=e(o,[["render",s]]);export{b as __pageData,p as default};
